public TMSRouteRateDetail KPMGCommon_initializeNegativeFuelOil(TMSRouteRateDetail _detail, XmlNode _xmlNode)
{
    if (_detail.RateType == TMSRateType::Accessorial)
    {
        TMSParameters               tMSParameters   = TMSParameters::find();
        WHSLoadTable                wHSLoadTable    = WHSLoadTable::find(Id);
        TMSRouteSegment             tMSRouteSegment = TMSRouteSegment::find(_detail.RouteCode, _detail.Sequence, true);
        TMSAccessorialAssignment    tMSAccessorialAssignment;
        TMSDeliveryUTCDateTime      unspecifiedDateTime = tMSRouteSegment.SailUTCDateTime;
        TMSDeliveryUTCDateTime      effectiveDateTime = tMSRouteSegment.ScheduledShipUTCDateTime;

        select firstonly tMSAccessorialAssignment
        where tMSAccessorialAssignment.CarrierCode == this.CarrierCode
           && (tMSAccessorialAssignment.CarrierServiceCode == '' ||tMSAccessorialAssignment.CarrierServiceCode == _detail.CarrierServiceCode)
           && tMSAccessorialAssignment.CarrierAccessorialId == tMSParameters.KPMGCommon_CarrierAccessorialNegativeId
           && tMSAccessorialAssignment.AccessorialAssignmentLevel == TMSAccessorialAssignmentLevel::Shipment
           && (tMSAccessorialAssignment.EffectiveUTCDateTimeFrom <= effectiveDateTime || tMSAccessorialAssignment.EffectiveUTCDateTimeFrom == unspecifiedDateTime)
           && (tMSAccessorialAssignment.EffectiveUTCDateTimeTo >= effectiveDateTime || tMSAccessorialAssignment.EffectiveUTCDateTimeTo == unspecifiedDateTime)
           && tMSAccessorialAssignment.FeeType == TMSFeeType::Percent
           && (tMSAccessorialAssignment.CurrencyCode == '' ||tMSAccessorialAssignment.CurrencyCode == _detail.CurrencyCode)
           && (tMSAccessorialAssignment.InventSiteId == '' || tMSAccessorialAssignment.InventSiteId == wHSLoadTable.InventSiteId )
           && (tMSAccessorialAssignment.InventLocationId == '' || tMSAccessorialAssignment.InventLocationId == wHSLoadTable.InventLocationId)
           && (tMSAccessorialAssignment.State == '' || tMSAccessorialAssignment.State == tMSRouteSegment.originPostalAddress().State)
           && (tMSAccessorialAssignment.PostalCodeLow == '' || tMSAccessorialAssignment.PostalCodeLow <= tMSRouteSegment.originPostalAddress().ZipCode)
           && (tMSAccessorialAssignment.PostalCodeHigh == '' || tMSAccessorialAssignment.PostalCodeHigh >= tMSRouteSegment.destinationPostalAddress().ZipCode)

           && (tMSAccessorialAssignment.CountryRegion == '' || tMSAccessorialAssignment.CountryRegion == tMSRouteSegment.originPostalAddress().CountryRegionId);

        if (tMSAccessorialAssignment.KPMGCommon_NegativeFuelOilPercentage)
        {
            ttsbegin;
            _detail.RateCur        = -_detail.RateCur;
            _detail.RateUnitRate   = -_detail.RateUnitRate;
            _detail.ShipperRate    = -_detail.ShipperRate;
            _detail.selectForUpdate(true);
            _detail.update();

            tMSRouteSegment.CustomerRate = tMSRouteSegment.CustomerRate + (_detail.RateCur * 2);
            tMSRouteSegment.ShipperRate  = tMSRouteSegment.ShipperRate + (_detail.ShipperRate * 2);
            tMSRouteSegment.RateCur      = tMSRouteSegment.RateCur + (_detail.RateCur * 2);
            tMSRouteSegment.update();
            ttscommit;
        }
    }

    return _detail;
}

public XmlNode KPMGCommon_initializeXmlNodeNegativeFuelOil(TMSRouteRateDetail _detail, XmlNode _xmlNode)
{
    if (_detail.RateType == TMSRateType::Accessorial && _detail.RateCur < 0)
    {
        this.writeNode(_xmlNode, #totalRate, num2str(_detail.RateCur,10,4,2,0));
        this.writeNode(_xmlNode, #unitRate, num2str(_detail.RateUnitRate,10,4,2,0));
    }

    return _xmlNode;
}

public void readAppSalesLine(XmlNode _xmlNode, SalesLine _salesLine)
{
    SalesLine                   salesLine = _salesLine;
    MarkupTrans                 markupTrans;
    MarkupTable                 markupTable;
    XmlNodeList                 appList;
    XmlNode                     appNode;
    XmlNodeList                 rateList;
    XmlNode                     rateNode;
    TMSRateType                 rateType;
    TMSId                       code;
    DlvTerm                     dlvTerm;
    RefRecId                    freightBillRecId;
    TMSFreightBillDetail        freightBillDetail;

    appList         = _xmlNode.selectNodes(#apportionment);
    appNode         = appList.nextNode();
    dlvTerm         = DlvTerm::find(freightTerm);

    if (appNode)
    {
        rateList    = appNode.selectNodes(#rate);
        rateNode    = rateList.nextNode();

        while (rateNode)
        {
            rateType            = str2int(this.returnNamedNode(rateNode, #rateType));
            code                = this.returnNamedNode(rateNode, #code);
            freightBillRecId    = str2int64(this.returnNamedNode(rateNode, #objectId));
            str rateTotalTXT = num2str(TMSFreightBillDetail::find(freightBillRecId).RateCur,10,4,1,0);
            if (TMSFreightBillDetail::find(freightBillRecId).RateCur != any2real(this.returnNamedNode(rateNode, #totalRate)))
                this.writeNode(rateNode, #totalRate, rateTotalTXT);

            rateNode = rateList.nextNode();
        }
    }

    next readAppSalesLine(_xmlNode, _salesLine);
}
